      parentTips: [
        {cn:"\u5982\u679c\u5bb6\u91cc\u6709\u5ba0\u7269\uff0c\u548c\u5b69\u5b50\u4e00\u8d77\u89c2\u5bdf\u5b83\u7684\u884c\u4e3a\uff0c\u8bb0\u5f55\u4e0b\u6765",en:"If you have a pet, observe its behavior together with your child and record it"}
      ]
